    dryrun: { question: "nums=[-1,2,1,-4] sorted=[-4,-1,1,2], target=1. i=0(-4): l=1(-1),r=3(2). sum=-4-1+2=-3. closest=-3. sum<1: l++. l=2(1),r=3(2). sum=-4+1+2=-1. |−1-1|=2<|−3-1|=4: closest=-1. l++. l≥r. i=1(-1): l=2(1),r=3(2). sum=-1+1+2=2. |2-1|=1<2: closest=2. sum>1: r--. l≥r. Return?", options: ["2","−1","−3"], correct: 0, explanation: "closest=2 (triplet [-1,1,2] sums to 2, distance 1 from target 1). This is better than -1 (distance 2) and -3 (distance 4). Return 2." },
    pushback: { challenge: "What if you need all triplets closest to the target (ties)?", options: ["Track minimum distance AND collect all sums achieving it. Modify algorithm: if |sum-target|==minDist: add to result list; if <minDist: clear list, add. O(n²).","Same algorithm works","Need brute force for ties"], correct: 0, explanation: "Ties: maintain minDist and resultList. When new sum ties minDist: append. When better: reset list. Same O(n²) loop. Return list of tied sums (or triplets)." },
