    clarify: { question: "What would you clarify?", options: ["Input sorted, output must also be sorted?","Can input have negatives?","In-place or new array?","What if all same magnitude?","Return sorted squares?"], mustAsk: [0,1,3], explanation: "Input sorted, output sorted ascending. Yes, negatives allowed (key challenge). New array (result). Handle equal magnitudes: tie-break doesn't matter. Return sorted squares." },
    steps: [
      { id: "understand", label: "Problem Understanding", emoji: "🔍", prompt: "Why does sorting the squared array naively take O(n log n), and how can you do it in O(n)?", why: { question: "What property of the input array enables O(n) squaring + sorting?", options: ["Sorted input means squares are already sorted","Sorted by value, but squaring reverses order for negatives. However, largest squares come from either end (most negative or most positive). Two pointers exploit this structure.","Must sort after squaring"], correct: 1, explanation: "Squares of sorted array form a 'valley' shape: large on left (negatives), small in middle (near zero), large on right (positives). Two pointers from both ends, filling result from right, gives sorted squares in O(n)." } },
      { id: "brute", label: "Brute Force", emoji: "🔨", prompt: "How would you square all elements and sort? What's the complexity?", why: { question: "Why O(n log n) for the naive approach?", options: ["O(n) — sorting sorted array is fast","Square each element: O(n). Sort squared array: O(n log n) (no longer sorted — negatives scramble order). Total O(n log n).","O(n²)"], correct: 1, explanation: "Square: O(n). Sort result: O(n log n) — squaring destroys the sorted order for negative numbers. Two-pointer leverages the original sorted structure for O(n)." } },
      { id: "pattern", label: "Pattern Recognition", emoji: "🧩", prompt: "Why do the largest squares always come from one of the two ends of the input array?", why: { question: "Why is max(nums[l]², nums[r]²) always the globally largest square remaining?", options: ["Coincidence","Input is sorted: most negative value is at left, most positive at right. Their squares are largest. After removing one end, the next largest is again at one of the two ends.","Only works for positive arrays"], correct: 1, explanation: "Sorted array: extremes are at ends. Squaring: extremes become largest squares. After placing the max, the next largest is at one of the remaining ends. This is a classic 'merge from ends' pattern." } },
      { id: "algorithm", label: "Algorithm Design", emoji: "⚙️", prompt: "Walk through: compare |nums[l]| and |nums[r]|, place larger square at result[pos].", why: { question: "Why fill result from RIGHT to LEFT?", options: ["Arbitrary — can fill either direction","We place the LARGEST squares first. Natural to fill from end of result array to beginning. pos starts at n-1, decrements.","Must fill left to right with smallest first"], correct: 1, explanation: "Each step produces the next largest remaining square. Output array filled from right (largest) to left (smallest). pos=n-1, decrement each step. Two pointers (l,r) advance inward." } },
      { id: "tradeoff", label: "Trade-off", emoji: "⚖️", prompt: "O(n) two-pointer vs O(n log n) sort. When would you use sort anyway?", why: { question: "Any scenario where O(n log n) sort is preferable here?", options: ["Never — O(n) always better","If input is not sorted: can't use two-pointer, must sort after squaring. Also: code simplicity — one-liner map+sort is cleaner for small n where performance doesn't matter.","Sort is never preferable"], correct: 1, explanation: "Unsorted input: sort-after-square O(n log n) necessary. Sorted input + performance-critical: two-pointer O(n). For small n: sort(map(nums, sq)) readability beats 20-line two-pointer." } },
      { id: "complexity", label: "Complexity", emoji: "📊", prompt: "Time and space complexity?", why: { question: "Why O(n) time and O(n) space?", options: ["O(n) time O(1) space","O(n) time: two pointers traverse n elements total. O(n) space: result array of n elements (can't avoid extra space — output must be separate array).","O(n log n)"], correct: 1, explanation: "Two pointers: each element placed exactly once. O(n) time. Result array: O(n) space (required — can't square in-place and maintain sorted order). Total: O(n) time O(n) space." } },
      { id: "edge", label: "Edge Cases", emoji: "🔐", prompt: "What edge cases exist?", why: { question: "All negative nums=[-3,-2,-1]: what is the output?", options: ["[1,4,9]","[9,4,1] — wait, output must be sorted ascending so [1,4,9]. Two pointers: l=0(-3,sq=9), r=2(-1,sq=1). 9>1: place 9 at result[2], l++. l=1(-2,sq=4), r=2(-1,sq=1). 4>1: place 4 at result[1], l++. l=2=r: place 1. Result [1,4,9].","[−9,−4,−1]"], correct: 0, explanation: "[1,4,9]. Squares of negatives are positive. Sorted ascending. Two-pointer from ends fills [9,4,1] right-to-left → result=[1,4,9]. Correct." } },
    ],
    dryrun: { question: "nums=[-4,-1,0,3,10]. l=0(-4,sq=16),r=4(10,sq=100). 100>16: result[4]=100, r=3(3,sq=9). 16>9: result[3]=16, l=1(-1,sq=1). 9>1: result[2]=9, r=2(0,sq=0). 1>0: result[1]=1, l=2. l==r(0,sq=0): result[0]=0. Final result=?", options: ["[0,1,9,16,100]","[0,1,9,100,16]","[100,16,9,1,0]"], correct: 0, explanation: "[0,1,9,16,100]. Filled right-to-left: [100,16,9,1,0] → rearranged to ascending output as result array filled from pos=4..0." },
    pushback: { challenge: "What if the array is not sorted but you still want sorted squares in O(n)?", options: ["Can't do O(n) without sorting. O(n log n) required: square all, then sort. The two-pointer trick relies entirely on the sorted input property.","Same two-pointer","Use counting sort if values bounded"], correct: 0, explanation: "Unsorted: two-pointer doesn't work (extremes aren't necessarily max squares). Must sort after squaring: O(n log n). Or if values bounded by B: counting sort O(n + B). No O(n) general solution." },
    followup: { question: "What if you want sorted cubes instead of squares? Does the algorithm change?", options: ["Yes — cubes preserve sign (negative cubed = negative). Sorted input stays sorted after cubing if all non-negative, or reverses for negatives. Can still use merge-like approach in O(n) but logic differs.","Identical algorithm","Sort after cubing always"], correct: 0, explanation: "Cubes: negative cubes are negative. Input [-4,-1,0,3,10] cubed: [-64,-1,0,27,1000]. Already sorted! No reordering needed — cubes of sorted array are sorted. But [-4,-1,3]: [-64,-1,27] — still sorted. For non-mixed arrays, cubes preserve order. Edge case: mixed signs with cube magnitudes." },
